CREATE TABLE IF NOT EXISTS faith_messages (
id INTEGER PRIMARY KEY AUTOINCREMENT,
message TEXT NOT NULL,
reference TEXT,
kind TEXT NOT NULL DEFAULT 'encouragement' CHECK(kind IN ('verse','encouragement','prayer','saying')),
verse_text TEXT,
verse_reference TEXT,
status TEXT NOT NULL DEFAULT 'approved' CHECK(status IN ('approved','draft')),
created_at TEXT NOT NULL DEFAULT (datetime('now')),
UNIQUE(message, reference)
);
CREATE INDEX IF NOT EXISTS idx_faith_messages_status_kind ON faith_messages(status, kind);
ALTER TABLE faith_messages ADD COLUMN verse_text TEXT;
ALTER TABLE faith_messages ADD COLUMN verse_reference TEXT;
-- If the ALTER TABLE statements above say duplicate column name, that is okay. Continue with the INSERT statements below.
